type StructuredFinancialData = {
  revenue: number | null
  profit: number | null
  growth: number | null
  latest_price: number | null
  PE_ratio: number | null
}

type StructuredFinancialAnalysisInput = {
  company: string
  data: StructuredFinancialData
}

type StructuredFinancialAnalysisOutput = {
  analysis: string
  strengths: string[]
  risks: string[]
}

function round(value: number): number {
  return Math.round(value * 100) / 100
}

function formatNumber(value: number | null): string {
  if (value === null || !Number.isFinite(value)) {
    return 'N/A'
  }

  return new Intl.NumberFormat('en-US', { maximumFractionDigits: 2 }).format(value)
}

export class FinancialDataAnalysisService {
  static analyze(
    input: StructuredFinancialAnalysisInput
  ): StructuredFinancialAnalysisOutput {
    const { company, data } = input
    const strengths: string[] = []
    const risks: string[] = []
    const observations: string[] = []

    observations.push(`Analysis for ${company} is based only on the provided structured financial data.`)

    if (data.revenue !== null) {
      observations.push(`Reported revenue is ${formatNumber(data.revenue)}.`)
    } else {
      risks.push('Revenue data is unavailable, which limits trend and margin analysis.')
    }

    if (data.profit !== null) {
      observations.push(`Reported profit is ${formatNumber(data.profit)}.`)

      if (data.profit > 0) {
        strengths.push(`The company is profitable based on the provided profit figure of ${formatNumber(data.profit)}.`)
      } else if (data.profit < 0) {
        risks.push(`The company is loss-making based on the provided profit figure of ${formatNumber(data.profit)}.`)
      } else {
        risks.push('Profit is zero in the provided data.')
      }
    } else {
      risks.push('Profit data is unavailable, so profitability cannot be fully evaluated.')
    }

    if (data.revenue !== null && data.profit !== null && data.revenue !== 0) {
      const profitMargin = round((data.profit / data.revenue) * 100)
      observations.push(`Calculated profit margin is ${profitMargin}%.`)

      if (profitMargin > 0) {
        strengths.push(`Profit margin is positive at ${profitMargin}%.`)
      } else if (profitMargin < 0) {
        risks.push(`Profit margin is negative at ${profitMargin}%.`)
      }
    }

    if (data.growth !== null) {
      observations.push(`Reported growth is ${round(data.growth)}%.`)

      if (data.growth > 0) {
        strengths.push(`Growth is positive at ${round(data.growth)}%.`)
      } else if (data.growth < 0) {
        risks.push(`Growth is negative at ${round(data.growth)}%.`)
      } else {
        risks.push('Growth is flat at 0% in the provided data.')
      }
    } else {
      risks.push('Growth data is unavailable, so growth trend analysis is limited.')
    }

    if (data.latest_price !== null) {
      observations.push(`Latest price is ${formatNumber(data.latest_price)}.`)
    } else {
      risks.push('Latest price data is unavailable.')
    }

    if (data.PE_ratio !== null) {
      observations.push(`P/E ratio is ${round(data.PE_ratio)}.`)

      if (data.profit !== null && data.profit > 0) {
        strengths.push(`A positive earnings figure supports interpretation of the reported P/E ratio of ${round(data.PE_ratio)}.`)
      } else {
        risks.push(`The reported P/E ratio of ${round(data.PE_ratio)} should be treated cautiously because earnings data is non-positive or incomplete.`)
      }
    } else {
      risks.push('P/E ratio is unavailable, which limits valuation comparison.')
    }

    if (data.PE_ratio !== null && data.growth !== null) {
      if (data.PE_ratio > data.growth) {
        observations.push(`The reported P/E ratio is numerically above the reported growth rate.`)
      } else if (data.PE_ratio < data.growth) {
        observations.push(`The reported P/E ratio is numerically below the reported growth rate.`)
      } else {
        observations.push(`The reported P/E ratio matches the reported growth rate numerically.`)
      }
    }

    if (strengths.length === 0) {
      strengths.push('No clear quantitative strength can be stated from the provided data alone.')
    }

    if (risks.length === 0) {
      risks.push('No specific quantitative risk is visible in the provided fields alone.')
    }

    return {
      analysis: observations.join(' '),
      strengths,
      risks,
    }
  }
}
